package com.xda.sa2ration.manufacturer;
import com.xda.sa2ration.backend.BackendCapabilities;import com.xda.sa2ration.backend.CapabilityStatus;import java.util.Locale;
abstract class PropertyManufacturerBackend implements ManufacturerBackend {private final String id;private final String[]tokens;PropertyManufacturerBackend(String id,String...tokens){this.id=id;this.tokens=tokens;}public String id(){return id;}public boolean matches(String signals){String s=signals==null?"":signals.toLowerCase(Locale.US);for(String token:tokens)if(s.contains(token))return true;return false;}public BackendCapabilities capabilities(){return new BackendCapabilities().set("linearColorMatrix",CapabilityStatus.UNTESTED).set("brightness",CapabilityStatus.UNKNOWN).set("refreshRate",CapabilityStatus.UNKNOWN).set("hbm",CapabilityStatus.UNKNOWN).set("dcDimming",CapabilityStatus.UNKNOWN).set("lut1d",CapabilityStatus.REQUIRES_MODULE).set("lut3d",CapabilityStatus.REQUIRES_MODULE);}}
